solutions.javascript:
// Function to validate a Git cherry-picked commit hash
function validateCherryPickHash(hash) {
    // Check if the hash is a string
    if (typeof hash !== 'string') {
        return false;
    }
    // Check if the hash matches the expected format using a regular expression
    const regex = /^[a-f0-9]{40}$/i;
    if (!regex.test(hash)) {
        return false;
    }
    // If the hash is 40 characters long (long commit hash) or 7 characters long (short commit hash), return true
    if (hash.length === 40 || hash.length === 7) {
        return true;
    }
    // If none of the above conditions are met, return false
    return false;
}
